parameters.jsonBody:
={
  "channel": "{{ $node['Extract Slack Data'].json.channel_id }}",
  "text": "<@{{ $node['Extract Slack Data'].json.user_id }}> It looks like you sent an empty request. Please use the command like this:\n`/updateplaybook [Describe what changed and what the new information is.]`\nNo need to specify the section; I will find that myself."
}

={
  "model": "claude-opus-4-6",
  "max_tokens": 4000,
  "system": {{ JSON.stringify($node['System Prompt'].json.system_prompt) }},
  "messages": [
    {
      "role": "user",
      "content": "UPDATE REQUEST FROM <@" + $node['Extract Slack Data'].json.user_id + ">:\n" + $node['Extract Slack Data'].json.request_text + "\n\nCURRENT PAGE VERSION: " + $node['Read Confluence Page'].json.version.number + "\n\nCURRENT PLAYBOOK CONTENT (Confluence Storage Format):\n" + $node['Read Confluence Page'].json.body.storage.value
    }
  ]
}

={
  "channel": "{{ $node['Extract Slack Data'].json.channel_id }}",
  "blocks": [
    {
      "type": "section",
      "text": { "type": "mrkdwn", "text": "<@{{ $node['Extract Slack Data'].json.user_id }}> Here is the draft based on your request. Please review and approve or reject below." }
    },
    {
      "type": "section",
      "text": { "type": "mrkdwn", "text": "*Your Request:*\n{{ $node['Extract Slack Data'].json.request_text }}" }
    },
    {
      "type": "section",
      "text": { "type": "mrkdwn", "text": "*Draft Prepared by Agent:*\n{{ $node['Claude API - Draft'].json.content[0].text.split('---CONFLUENCE BODY START---')[0] }}" }
    },
    {
      "type": "actions",
      "block_id": "approval_actions",
      "elements": [
        { "type": "button", "text": { "type": "plain_text", "text": "✅ Approve" }, "style": "primary", "action_id": "approve_draft", "value": "approve" },
        { "type": "button", "text": { "type": "plain_text", "text": "❌ Reject" }, "style": "danger", "action_id": "reject_draft", "value": "reject" }
      ]
    }
  ]
}

={
  "version": { "number": {{ $node['Read Confluence Page'].json.version.number + 1 }} },
  "title": "{{ $node['Read Confluence Page'].json.title }}",
  "type": "page",
  "body": {
    "storage": {
      "value": {{ JSON.stringify($node['Claude API - Draft'].json.content[0].text.split('---CONFLUENCE BODY START---')[1].split('---CONFLUENCE BODY END---')[0].trim()) }},
      "representation": "storage"
    }
  }
}

={
  "channel": "{{ $node['Extract Button Data'].json.button_channel_id }}",
  "thread_ts": "{{ $node['Extract Button Data'].json.button_thread_ts }}",
  "text": "<@{{ $node['Extract Button Data'].json.button_user_id }}> Done. The playbook has been updated successfully.

*Section updated:* {{ $node['Extract Button Data'].json.original_draft.match(/SECTION: (.+)/)?.[1] || 'See playbook' }}
*Change type:* {{ $node['Extract Button Data'].json.original_draft.match(/CHANGE TYPE: (.+)/)?.[1] || 'See playbook' }}

View the updated playbook: {{ $env.CONFLUENCE_BASE_URL }}/wiki/pages/viewpage.action?pageId={{ $env.CONFLUENCE_PAGE_ID }}"
}

={
  "channel": "{{ $node['Extract Button Data'].json.button_channel_id }}",
  "thread_ts": "{{ $node['Extract Button Data'].json.button_thread_ts }}",
  "text": "<@{{ $node['Extract Button Data'].json.button_user_id }}> Got it; that draft has been rejected. Please reply in this thread and tell me specifically what was wrong. Was it the wrong section, incorrect content or the wrong writing style?"
}

={
  "channel": "{{ $env.SLACK_CHANNEL_ID }}",
  "blocks": [
    {
      "type": "section",
      "text": { "type": "mrkdwn", "text": "<@{{ $node['Listen for Clarification Reply'].json.user }}> Here is the revised draft based on your feedback." }
    },
    {
      "type": "section",
      "text": { "type": "mrkdwn", "text": "*Revised Draft:*\n{{ $node['Claude API - Revised Draft'].json.content[0].text.split('---CONFLUENCE BODY START---')[0] }}" }
    },
    {
      "type": "actions",
      "block_id": "approval_actions_revised",
      "elements": [
        { "type": "button", "text": { "type": "plain_text", "text": "✅ Approve" }, "style": "primary", "action_id": "approve_draft", "value": "approve" },
        { "type": "button", "text": { "type": "plain_text", "text": "❌ Reject" }, "style": "danger", "action_id": "reject_draft_final", "value": "reject_final" }
      ]
    }
  ]
}

={
  "channel": "{{ $env.SLACK_CHANNEL_ID }}",
  "text": "<@{{ $node['Listen for Clarification Reply'].json.user }}> This update has been rejected twice. No changes have been made to the playbook. Please make this edit manually or contact your admin for assistance."
}
